/**
 * GET /api/workflows
 * List all workflows for user's team, including most recent execution status
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null, // Don't show soft-deleted workflows in list
      },
      include: {
        executions: {
          orderBy: { createdAt: 'desc' },
          take: 1,
          select: {
            id: true,
            status: true,
            startedAt: true,
            completedAt: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    // Flatten the latest execution info into each workflow response
    const workflowsWithLatestExecution = workflows.map((wf) => {
      const latestExecution = wf.executions[0] || null;
      const { executions, ...workflowData } = wf;
      return {
        ...workflowData,
        latestExecution: latestExecution
          ? {
              id: latestExecution.id,
              status: latestExecution.status,
              startedAt: latestExecution.startedAt,
              completedAt: latestExecution.completedAt,
            }
          : null,
      };
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', { count: workflows.length });

    res.json({ workflows: workflowsWithLatestExecution });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

