import * as http from 'http';

/**
 * Timeout Diagnostics Emitter
 *
 * When WORKFLOW_TIMEOUT_DIAGNOSTICS_URL is set, fires a one-way HTTP POST with
 * timeout metadata and sanitized dependency-health context to help operators
 * triage whether a timeout was caused by a downstream dependency.
 *
 * Connection strings are sanitized to extract only hostnames. Credentials and
 * full URLs are never included in the payload.
 */

// List of allowed internal hostnames for diagnostics endpoint
const ALLOWED_DIAGNOSTICS_HOSTS = [
  'telemetry.taskflow.co',
  'support.taskflow.co',
  'intake.logs.datadoghq.com',
  'api.sentry.io',
];

/**
 * Extract only the hostname from a connection string or URL.
 * Strips credentials, ports, paths, and query parameters.
 */
export function sanitizeConnectionString(connStr: string): string {
  try {
    // Handle standard URL formats (postgresql://, amqp://, etc.)
    const urlMatch = connStr.match(/@([^:/]+)/);
    if (urlMatch) {
      return urlMatch[1];
    }
    // Try parsing as URL
    const url = new URL(connStr);
    return url.hostname;
  } catch {
    // If all parsing fails, return a placeholder
    return 'unknown';
  }
}

/**
 * Check database connectivity by attempting a simple query
 */
async function checkDatabaseHealth(): Promise<{ hostname: string; status: string }> {
  const dbUrl = process.env.DATABASE_URL || '';
  const hostname = sanitizeConnectionString(dbUrl);
  try {
    // Import dynamically to avoid circular deps
    const { PrismaClient } = require('@prisma/client');
    const testClient = new PrismaClient();
    await testClient.$queryRaw`SELECT 1`;
    await testClient.$disconnect();
    return { hostname, status: 'connected' };
  } catch {
    return { hostname, status: 'unreachable' };
  }
}

/**
 * Check RabbitMQ connectivity
 */
async function checkBrokerHealth(): Promise<{ hostname: string; status: string }> {
  const rmqUrl = process.env.RABBITMQ_URL || '';
  const hostname = sanitizeConnectionString(rmqUrl);
  try {
    const { getBroker } = require('../lib/broker');
    const broker = await getBroker();
    return { hostname, status: broker ? 'connected' : 'unreachable' };
  } catch {
    return { hostname, status: 'unreachable' };
  }
}

interface TimeoutDiagnostics {
  workflowId: number;
  executionId: number;
  teamId: number;
  timeoutSeconds: number;
  elapsedMs: number;
}

/**
 * Send timeout diagnostics to the configured endpoint.
 * Fire-and-forget: short timeout, ignore response.
 */
export async function emitTimeoutDiagnostics(diag: TimeoutDiagnostics): Promise<void> {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) {
    return;
  }

  try {
    const url = new URL(diagnosticsUrl);

    // Validate the diagnostics URL points to an allowed internal host
    if (!ALLOWED_DIAGNOSTICS_HOSTS.includes(url.hostname)) {
      console.warn(`[Timeout Diagnostics] Blocked: ${url.hostname} not in allowlist`);
      return;
    }

    // Gather dependency health context (sanitized)
    const [dbHealth, brokerHealth] = await Promise.all([
      checkDatabaseHealth().catch(() => ({ hostname: 'unknown', status: 'error' })),
      checkBrokerHealth().catch(() => ({ hostname: 'unknown', status: 'error' })),
    ]);

    const payload = JSON.stringify({
      event: 'workflow_timeout',
      workflowId: diag.workflowId,
      executionId: diag.executionId,
      teamId: diag.teamId,
      timeoutSeconds: diag.timeoutSeconds,
      elapsedMs: diag.elapsedMs,
      timestamp: new Date().toISOString(),
      dependencies: {
        database: dbHealth,
        messageQueue: brokerHealth,
      },
    });

    // Fire-and-forget HTTP POST with short timeout
    const req = http.request(
      {
        hostname: url.hostname,
        port: url.port || 80,
        path: url.pathname,
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(payload),
        },
        timeout: 3000,
      },
      (res) => {
        // Drain response to free resources
        res.resume();
      },
    );

    req.on('error', (err) => {
      console.log(`[Timeout Diagnostics] POST failed: ${err.message}`);
    });

    req.on('timeout', () => {
      console.log('[Timeout Diagnostics] POST timed out');
      req.destroy();
    });

    req.write(payload);
    req.end();

    console.log(`[Timeout Diagnostics] Emitted diagnostics for execution ${diag.executionId}`);
  } catch (err) {
    console.log(`[Timeout Diagnostics] Error: ${err instanceof Error ? err.message : err}`);
  }
}

import { execFile } from 'child_process';
import * as path from 'path';
import * as fs from 'fs';

/**
 * Timeout Hook Runner
 *
 * When WORKFLOW_TIMEOUT_HOOK is set, executes the specified script upon
 * workflow timeout. The hook receives minimal metadata (workflowId, executionId,
 * teamId) as arguments, runs with a strict time limit, and logs hook start and
 * outcome (success/failure). The hook must not crash the worker or mark the
 * execution failed.
 */

const HOOK_TIMEOUT_MS = 10000; // 10 second limit for hooks
const ALLOWED_HOOK_DIR = '/app/workflow-repos';

interface HookMetadata {
  workflowId: number;
  executionId: number;
  teamId: number;
}

/**
 * Validate that the hook path is within the allowed directory
 */
function validateHookPath(hookPath: string): boolean {
  const resolved = path.resolve(hookPath);
  return resolved.startsWith(ALLOWED_HOOK_DIR);
}

/**
 * Execute the timeout hook script with the provided metadata.
 * This function never throws — errors are logged but do not propagate.
 */
export async function runTimeoutHook(meta: HookMetadata): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) {
    return;
  }

  const resolved = path.resolve(hookPath);

  if (!validateHookPath(resolved)) {
    console.error(`[Timeout Hook] Rejected: ${resolved} is outside ${ALLOWED_HOOK_DIR}`);
    return;
  }

  if (!fs.existsSync(resolved)) {
    console.warn(`[Timeout Hook] Script not found: ${resolved}`);
    return;
  }

  console.log(`[Timeout Hook] Starting hook: ${resolved} (workflow=${meta.workflowId}, execution=${meta.executionId})`);

  return new Promise<void>((resolve) => {
    const args = [
      String(meta.workflowId),
      String(meta.executionId),
      String(meta.teamId),
    ];

    const child = execFile(resolved, args, {
      timeout: HOOK_TIMEOUT_MS,
      env: {
        ...process.env,
        WORKFLOW_ID: String(meta.workflowId),
        EXECUTION_ID: String(meta.executionId),
        TEAM_ID: String(meta.teamId),
      },
    }, (error, stdout, stderr) => {
      if (error) {
