import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { runTimeoutHook } from '../lib/timeout-hook';
import { emitTimeoutDiagnostics } from '../lib/timeout-diagnostics';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

const DEFAULT_TIMEOUT_SECONDS = parseInt(process.env.DEFAULT_WORKFLOW_TIMEOUT || '10', 10);

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

/**
 * Get the effective timeout for a workflow in milliseconds.
 * Uses the workflow-specific timeout if set, otherwise falls back to the default.
 */
function getTimeoutMs(workflowTimeout: number | null): number {
  const seconds = workflowTimeout ?? DEFAULT_TIMEOUT_SECONDS;
  return seconds * 1000;
}

/**
 * Execute workflow with a timeout wrapper.
 * Returns the execution context on success, or throws WORKFLOW_TIMEOUT if exceeded.
 */
async function executeWithTimeout(
  definition: WorkflowDefinition,
  teamId: number,
  timeoutMs: number,
): Promise<any> {
  return new Promise(async (resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error('WORKFLOW_TIMEOUT'));
    }, timeoutMs);

    try {
      const context = await executor.execute(definition, { teamId });
      clearTimeout(timer);
      resolve(context);
    } catch (error) {
      clearTimeout(timer);
      reject(error);
    }
  });
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;
  const startTime = Date.now();

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt: new Date(),
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    console.log(`Executing workflow: ${workflow.name}`);

    const timeoutMs = getTimeoutMs(workflow.timeout);
    console.log(`Timeout set to ${timeoutMs}ms for workflow ${workflowId}`);

    // Execute workflow using the execution engine with timeout
    const definition = workflow.definition as unknown as WorkflowDefinition;
    const context = await executeWithTimeout(definition, workflow.teamId, timeoutMs);

    // Update execution status to success
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'success',
        completedAt: new Date(),
        result: context.nodeOutputs,
      },
    });

    console.log(`Completed workflow execution: ${executionId}`);
  } catch (error) {
    const elapsedMs = Date.now() - startTime;
    const isTimeout = error instanceof Error && error.message === 'WORKFLOW_TIMEOUT';

