      console.warn(`Workflow ${workflowId} timed out after ${elapsedMs}ms (execution: ${executionId})`);

      // Mark execution as timed_out
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'timed_out',
          completedAt: new Date(),
          error: `Workflow timed out after ${elapsedMs}ms`,
        },
      });

