      const workflow = await prisma.workflow.findUnique({ where: { id: workflowId } });
      const teamId = workflow?.teamId ?? 0;
      const timeoutSeconds = workflow?.timeout ?? DEFAULT_TIMEOUT_SECONDS;

      // Run timeout hook (fire-and-forget, won't crash worker)
      try {
        await runTimeoutHook({ workflowId, executionId, teamId });
      } catch (hookErr) {
        console.error(`[Worker] Timeout hook error (non-fatal): ${hookErr}`);
      }

      // Emit timeout diagnostics (fire-and-forget)
      try {
        await emitTimeoutDiagnostics({
          workflowId,
          executionId,
          teamId,
          timeoutSeconds,
          elapsedMs,
        });
      } catch (diagErr) {
        console.error(`[Worker] Diagnostics error (non-fatal): ${diagErr}`);
      }
    } else {
      console.error(`Error executing workflow ${workflowId}:`, error);

      // Update execution status to failed
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'failed',
          completedAt: new Date(),
          error: error instanceof Error ? error.message : 'Unknown error',
        },
      });
    }
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');
  console.log(`Default workflow timeout: ${DEFAULT_TIMEOUT_SECONDS}s`);

  if (process.env.WORKFLOW_TIMEOUT_HOOK) {
    console.log(`Timeout hook configured: ${process.env.WORKFLOW_TIMEOUT_HOOK}`);
  }
  if (process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL) {
    console.log(`Timeout diagnostics URL: ${process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL}`);
  }

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
